public static int gcd(int u, int v) {
    if (u == 0 && v == 0) {
        return 0; // gcd(0, 0) is 0
    }
    if (u == 0) {
        return Math.abs(v); // gcd(0, v) is |v|
    }
    if (v == 0) {
        return Math.abs(u); // gcd(u, 0) is |u|
    }

    // Make u and v negative
    if (u > 0) {
        u = -u;
    }
    if (v > 0) {
        v = -v;
    }

    int k = 0;
    while ((u & 1) == 0 && (v & 1) == 0 && k < 31) {
        u /= 2;
        v /= 2;
        k++;
    }
    if (k == 31) {
        throw new ArithmeticException("overflow: gcd is 2^31");
    }

    int t = ((u & 1) == 1) ? v : -(u / 2);
    do {
        while ((t & 1) == 0) {
            t /= 2;
        }
        if (t > 0) {
            u = -t;
        } else {
            v = t;
        }
        t = (v - u) / 2;
    } while (t != 0);

    // Check for potential overflow before returning the result
    if (Math.abs((long) u) > Integer.MAX_VALUE / (1 << k)) {
        throw new ArithmeticException("overflow: gcd calculation exceeds integer range");
    }

    return Math.abs(u) * (1 << k);
}

